import{c as t,Q as e,j as r,m as o}from"./chunks/framework.BPKcPtvA.js";const p=JSON.parse('{"title":"How do I roll back a migration?","description":"","frontmatter":{},"headers":[],"relativePath":"guide/recipes/admin/rollback-migration.md","filePath":"guide/recipes/admin/rollback-migration.md","lastUpdated":1778912818000}'),i={name:"guide/recipes/admin/rollback-migration.md"};function l(n,a,s,c,d,h){return e(),r("div",null,[...a[0]||(a[0]=[o('<h1 id="how-do-i-roll-back-a-migration" tabindex="-1">How do I roll back a migration? <a class="header-anchor" href="#how-do-i-roll-back-a-migration" aria-label="Permalink to &quot;How do I roll back a migration?&quot;">​</a></h1><div class="tip custom-block"><p class="custom-block-title">Who can do this</p><p><strong>Platform Admin</strong> or <strong>Infra Ops</strong></p></div><p>Rollback returns tenants to the source instance from before the migration. It&#39;s only available for migration types that wrote a rollback artifact (instance-replace, tenant-copy).</p><h2 id="steps" tabindex="-1">Steps <a class="header-anchor" href="#steps" aria-label="Permalink to &quot;Steps&quot;">​</a></h2><ol><li>Open <strong>Migrations</strong> and find the migration to roll back.</li><li>Click the row to open the drawer.</li><li>In the drawer header, click <strong>Rollback</strong>.</li><li>The rollback dialog shows which tenants will be reverted. Confirm.</li></ol><h2 id="result" tabindex="-1">Result <a class="header-anchor" href="#result" aria-label="Permalink to &quot;Result&quot;">​</a></h2><p>A new job runs in reverse direction. Tenants return to the source instance with the data state captured at migration time. The original job is marked <strong>Rolled Back</strong>.</p><div class="warning custom-block"><p class="custom-block-title">Rollback windows are limited</p><p>Rollback artifacts expire after the retention period. After that, the <strong>Rollback</strong> button is disabled and you must recover manually.</p></div><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./rerun-migration">How do I rerun a failed migration?</a></li><li><a href="./triage-discrepancy">How do I triage a discrepancy?</a></li></ul>',10)])])}const u=t(i,[["render",l]]);export{p as __pageData,u as default};
